Javascript.validate:
			var code = Services.getValue(EnterBailiffID.dataBinding);
			var err = null;
		
			if( code < 1 || code > 98)  
			{err = ErrorCode.getErrorCode("CaseMan_rangeBetweenOneNinetyeight_Msg");
			}
    		else if( CaseManValidationHelper.validateNumber(code) == false )
			{err = ErrorCode.getErrorCode("Caseman_nonNumericPartyCode_Msg");
			}
			return err;
